 1	import React, { FC } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	
 4	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import { VirtualMachineDetailsTab } from '@kubevirt-utils/constants/tabs-constants';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { getNamespace } from '@kubevirt-utils/resources/shared';
 8	import useNamespaceUDN from '@kubevirt-utils/resources/udn/hooks/useNamespaceUDN';
 9	import { VirtualizedTable } from '@openshift-console/dynamic-plugin-sdk';
10	import { Card, CardBody, CardTitle, Divider } from '@patternfly/react-core';
11	
12	import { createURL } from '../../utils/utils';
13	
14	import VirtualMachinesOverviewTabNetworkFQDN from './components/VirtualMachinesOverviewTabNetworkFQDN';
15	import useVirtualMachinesOverviewTabInterfacesColumns from './hooks/useVirtualMachinesOverviewTabInterfacesColumns';
16	import useVirtualMachinesOverviewTabInterfacesData from './hooks/useVirtualMachinesOverviewTabInterfacesData';
17	import { InterfacesData } from './utils/types';
18	import VirtualMachinesOverviewTabNetworkInterfacesRow from './VirtualMachinesOverviewTabNetworkInterfacesRow';
19	
20	import './virtual-machines-overview-tab-interfaces.scss';
21	
22	type VirtualMachinesOverviewTabInterfacesProps = {
23	  vm: V1VirtualMachine;
24	  vmi: V1VirtualMachineInstance;
25	};
26	const VirtualMachinesOverviewTabInterfaces: FC<VirtualMachinesOverviewTabInterfacesProps> = ({
27	  vm,
28	  vmi,
29	}) => {
30	  const { t } = useKubevirtTranslation();
31	  const data = useVirtualMachinesOverviewTabInterfacesData(vm, vmi);
32	  const columns = useVirtualMachinesOverviewTabInterfacesColumns();
33	
34	  const [isNamespaceManagedByUDN] = useNamespaceUDN(getNamespace(vm));
35	
36	  return (
37	    <div className="VirtualMachinesOverviewTabInterfaces--main">
38	      <Card>
39	        <CardTitle className="text-muted">
40	          <Link
41	            to={createURL(
42	              `${VirtualMachineDetailsTab.Configurations}/${VirtualMachineDetailsTab.Network}`,
43	              location?.pathname,
44	            )}
45	          >
46	            {t('Network ({{count}})', { count: data?.length || 0 })}
47	          </Link>
48	        </CardTitle>
49	        <Divider />
50	        <CardBody isFilled>
51	          <VirtualizedTable<InterfacesData>
52	            NoDataEmptyMsg={() => (
53	              <div className="pf-v6-u-text-align-center no-data-empty-message">
54	                {t('No network interfaces found')}
55	              </div>
56	            )}
57	            columns={columns}
58	            data={data}
59	            loaded
60	            loadError={false}
61	            Row={VirtualMachinesOverviewTabNetworkInterfacesRow}
62	            unfilteredData={data}
63	          />
64	          {!isNamespaceManagedByUDN && <VirtualMachinesOverviewTabNetworkFQDN vm={vm} />}
65	        </CardBody>
66	      </Card>
67	    </div>
68	  );
69	};
70	
71	export default VirtualMachinesOverviewTabInterfaces;

